import React, { useState, useEffect } from 'react';
import { db } from '../firebase';
import { collection, getDocs, query, where } from 'firebase/firestore';
import { Search, Plus, LayoutGrid, User as UserIcon } from 'lucide-react';
import ProjectCard from '../components/ProjectCard';
import UserProfile from '../components/UserProfile'; // Ensure this is imported

function StudentHome({ user, onLogout, onSelectProject, onAddProject }) {
  const [projects, setProjects] = useState([]);
  const [searchQuery, setSearchQuery] = useState("");
  const [isProfileOpen, setIsProfileOpen] = useState(false); // 🚨 THE FIX: State to track if profile is open

  useEffect(() => {
    const fetchProjects = async () => {
      const q = query(collection(db, "projects"), where("status", "==", "Approved"));
      const querySnapshot = await getDocs(q);
      setProjects(querySnapshot.docs.map(doc => ({ id: doc.id, ...doc.data() })));
    };
    fetchProjects();
  }, []);

  const filteredProjects = projects.filter(p => 
    p.title.toLowerCase().includes(searchQuery.toLowerCase()) ||
    p.category?.toLowerCase().includes(searchQuery.toLowerCase())
  );

  return (
    <div className="min-h-screen bg-[#0a0a0a] text-white font-sans">
      {/* --- NAVBAR --- */}
      <nav className="border-b border-white/10 bg-black/50 backdrop-blur-xl sticky top-0 z-30">
        <div className="max-w-7xl mx-auto px-6 h-20 flex items-center justify-between">
          <div className="flex items-center gap-3">
            <div className="w-10 h-10 bg-indigo-600 rounded-xl flex items-center justify-center shadow-lg shadow-indigo-500/20">
              <LayoutGrid className="w-6 h-6 text-white" />
            </div>
            <h1 className="text-xl font-bold tracking-tight">CampusCanvas</h1>
          </div>

          <div className="flex items-center gap-4">
            <button 
              onClick={onAddProject}
              className="bg-white/5 hover:bg-white/10 border border-white/10 p-2.5 rounded-xl transition-all"
            >
              <Plus className="w-5 h-5 text-gray-400" />
            </button>
            
            {/* 🚨 PROFILE TRIGGER */}
            <button 
              onClick={() => setIsProfileOpen(true)} 
              className="w-10 h-10 rounded-xl bg-gradient-to-tr from-indigo-600 to-purple-600 flex items-center justify-center border border-white/20 shadow-lg hover:scale-105 transition-transform"
            >
              <UserIcon className="w-5 h-5 text-white" />
            </button>
          </div>
        </div>
      </nav>

      {/* --- MAIN CONTENT --- */}
      <main className="max-w-7xl mx-auto px-6 py-10">
        <div className="mb-10 flex flex-col md:flex-row md:items-center justify-between gap-6">
          <h2 className="text-3xl font-extrabold text-white">Project Gallery</h2>
          <div className="relative w-full md:w-96">
            <Search className="absolute left-4 top-1/2 -translate-y-1/2 w-5 h-5 text-gray-500" />
            <input 
              type="text" 
              placeholder="Search innovation..." 
              className="w-full bg-white/5 border border-white/10 rounded-2xl pl-12 pr-4 py-3.5 outline-none focus:border-indigo-500 transition-all"
              value={searchQuery}
              onChange={(e) => setSearchQuery(e.target.value)}
            />
          </div>
        </div>

        <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-8">
          {filteredProjects.map(project => (
            <ProjectCard key={project.id} project={project} onClick={() => onSelectProject(project)} />
          ))}
        </div>
      </main>

      {/* 🚨 THE MODAL CONNECTION */}
      {isProfileOpen && (
        <UserProfile 
          user={user} 
          onClose={() => setIsProfileOpen(false)} // 👈 This function kills the modal
          onLogout={onLogout} 
        />
      )}
    </div>
  );
}

export default StudentHome;
